import torch
from torch import nn
from torch.nn import functional as F
import torch.nn.init as init


class Single_Conv(nn.Module):
    def __init__(self, in_channel, out_channcel):
        super(Single_Conv, self).__init__()
        self.layer = nn.Sequential(
            nn.Conv2d(in_channel, out_channcel, 3, 1, 1, padding_mode='reflect', bias=False)
        )

    def forward(self, x):
        return self.layer(x)


class Conv_Block_single(nn.Module):
    def __init__(self, channel):
        super(Conv_Block_single, self).__init__()
        self.layer = nn.Sequential(
            nn.Conv2d(channel, channel, 3, 1, 1, padding_mode='reflect', bias=False),
            nn.BatchNorm2d(channel),
            #nn.Dropout2d(0.3),
            nn.LeakyReLU()
        )

    def forward(self, x):
        return self.layer(x)

    def init_weights(self):
        for m in self.modules():
            if isinstance(m, nn.Conv2d):
                # 使用He初始化（也称Kaiming初始化），适用于LeakyReLU
                init.kaiming_normal_(m.weight, mode='fan_out', nonlinearity='leaky_relu')
            elif isinstance(m, nn.BatchNorm2d):
                # 初始化批量正则层的权重
                init.constant_(m.weight, 1)
                # 初始化批量正则层的偏置
                init.constant_(m.bias, 0)


class Conv_Block_double(nn.Module):
    def __init__(self, in_channel, out_channel):
        super(Conv_Block_double, self).__init__()
        self.layer = nn.Sequential(
            nn.Conv2d(in_channel, out_channel, 3, 1, 1, padding_mode='reflect', bias=False),
            nn.BatchNorm2d(out_channel),
            #nn.Dropout2d(0.3),
            nn.LeakyReLU(),
            nn.Conv2d(in_channel, out_channel, 3, 1, 1, padding_mode='reflect', bias=False),
            nn.BatchNorm2d(out_channel),
            #nn.Dropout2d(0.3),
            nn.LeakyReLU(),
        )

    def forward(self, x):
        return self.layer(x)

    def init_weights(self):
        for m in self.modules():
            if isinstance(m, nn.Conv2d):
                # 使用He初始化（也称Kaiming初始化），适用于LeakyReLU
                init.kaiming_normal_(m.weight, mode='fan_out', nonlinearity='leaky_relu')
            elif isinstance(m, nn.BatchNorm2d):
