class UpSample(nn.Module):
    def __init__(self, channel):
        super(UpSample, self).__init__()
        self.layer = nn.Sequential(
            nn.Conv2d(channel, channel, 2, 1, 1, padding_mode='reflect', bias=False)
        )

    def forward(self, x, feature_map):
        up = F.interpolate(x, scale_factor=2, mode='bilinear')
        out = self.layer(up)
        return torch.cat((out, feature_map), dim=1)


class Deep_Res_UNET(nn.Module):
    def __init__(self, args):
        super(Deep_Res_UNET, self).__init__()
        self.c1 = Single_Conv(3,64)
        self.c2 = Conv_Block_single(64)
        self.c2.init_weights()
        self.d1 = DownSample(64, 128)
        self.d1.init_weights()
        self.c3 = Conv_Block_single(128)
        self.c3.init_weights()
        self.d2 = DownSample(128, 256)
        self.d2.init_weights()
        self.c4 = Conv_Block_single(256)
        self.c4.init_weights()
        self.d3 = DownSample(256, 512)
        self.d3.init_weights()
        self.c5 = Conv_Block_single(512)
        self.c5.init_weights()
        self.u1 = UpSample(512)
        self.c6 = Conv_Block_double(768, 256)
        self.c6.init_weights()
        self.u2 = UpSample(256)
        self.c7 = Conv_Block_double(384, 128)
        self.c7.init_weights()
        self.u3 = UpSample(128)
        self.c8 = Conv_Block_double(192, 64)
        self.c8.init_weights()
        self.out = Single_Conv(64, 1)
        self.Th = nn.Sigmoid()

    def forward(self, x):
        R1 = self.c1(x)
        R2 = self.c2(R1)

        R3 = R2 + nn.Conv2d(3, 64, 1, 1, 1, padding_mode='reflect', bias=False)

        R4 = self.d1(R3)
        R5 = self.c3(R4)

        R6 = R5 + nn.Conv2d(64, 128, 1, 2, 1, padding_mode='reflect', bias=False)
        R7 = self.d2(R6)
        R8 = self.c4(R7)

        R9 = R8 + nn.Conv2d(128,256, 1, 2, 1, padding_mode='reflect', bias=False)
        R10 = self.d3(R9)
        R11 = self.c5(R10)

        R12 = R11 + nn.Conv2d(256, 512, 1, 2, 1, padding_mode='reflect', bias=False)
        R13 = self.u1(R12, R9)

        R14 = self.c6(R13)
        R15 = R14 + nn.Conv2d(768, 256, 1, 1, 1, padding_mode='reflect', bias=False)

        R16 = self.u2(R15, R6)
        R17 = self.c7(R16)

        R18 = R17 + nn.Conv2d(384, 128, 1, 1, 1, padding_mode='reflect', bias=False)
        R19 = self.u3(R18, R3)

        R20 = self.c8(R19)
        R21 = R20 + nn.Conv2d(192, 64, 1, 1, 1, padding_mode='reflect', bias=False)

        return self.Th(self.out(R21))
